import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"北堂（西什库天主堂）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/beitang.md","filePath":"religion/beitang.md","lastUpdated":1784712887000}'),n={name:"religion/beitang.md"};function i(o,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北堂-西什库天主堂" tabindex="-1">北堂（西什库天主堂） <a class="header-anchor" href="#北堂-西什库天主堂" aria-label="Permalink to &quot;北堂（西什库天主堂）&quot;">​</a></h1><blockquote><p>&quot;北京最华丽的天主教堂，哥特式建筑的杰作。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北堂，又称西什库教堂、救世主教堂，是北京最大、最宏伟的天主教堂，也是中国最美的教堂之一。教堂采用哥特式建筑风格，高耸的尖塔、精美的玫瑰窗、宏伟的内部空间，使其成为北京西什库地区的地标性建筑。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-1.5小时</td></tr><tr><td style="text-align:left;"><strong>弥撒时间</strong></td><td style="text-align:left;">平日6:30、18:30，周日6:30、8:00、10:00、18:00</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线西四站D口</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西什库大街33号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>北堂始建于清康熙三十二年（1693年），由法国传教士张诚、白晋等人主持修建。最初建在皇城西安门内的蚕池口，称&quot;救世主堂&quot;。</p><h3 id="迁址重建" tabindex="-1">迁址重建 <a class="header-anchor" href="#迁址重建" aria-label="Permalink to &quot;迁址重建&quot;">​</a></h3><p>清康熙五十一年（1703年），因教堂位于皇城之内，清廷要求迁出。教堂迁至西什库，即今址。光绪十二年（1886年），因西什库教堂影响中南海紫光阁扩建，再次迁至西什库今址。</p><h3 id="扩建" tabindex="-1">扩建 <a class="header-anchor" href="#扩建" aria-label="Permalink to &quot;扩建&quot;">​</a></h3><p>光绪十四年（1888年），慈禧太后拨银扩建北堂，由法国传教士主持，建成今日所见的哥特式建筑。新堂于光绪十六年（1890年）落成。</p><h3 id="义和团运动" tabindex="-1">义和团运动 <a class="header-anchor" href="#义和团运动" aria-label="Permalink to &quot;义和团运动&quot;">​</a></h3><p>光绪二十六年（1900年），义和团运动爆发，北堂被义和团和清军围攻长达两个月。当时有3000余名中国教友和数十位外国传教士在北堂内坚守。后在八国联军增援下解围。</p><h3 id="近代发展" tabindex="-1">近代发展 <a class="header-anchor" href="#近代发展" aria-label="Permalink to &quot;近代发展&quot;">​</a></h3><p>1958年，北堂关闭。1985年，在修复后重新开放，成为北京天主教重要的活动场所。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="哥特式建筑" tabindex="-1">哥特式建筑 <a class="header-anchor" href="#哥特式建筑" aria-label="Permalink to &quot;哥特式建筑&quot;">​</a></h3><p>北堂是典型的哥特复兴式建筑，具有哥特式建筑的所有典型特征：</p><ul><li><strong>尖塔</strong>：三座高耸的尖塔直指苍穹</li><li><strong>尖拱</strong>：门窗采用尖拱造型</li><li><strong>飞扶壁</strong>：外墙有飞扶壁结构</li><li><strong>玫瑰窗</strong>：正门上方有精美的玫瑰窗</li><li><strong>彩色玻璃</strong>：内部有彩绘玻璃长窗</li></ul><h3 id="外观特征" tabindex="-1">外观特征 <a class="header-anchor" href="#外观特征" aria-label="Permalink to &quot;外观特征&quot;">​</a></h3><ul><li><strong>尖塔</strong>：主塔高约30米，两侧各有一座高塔</li><li><strong>外墙</strong>：灰色砖石结构，庄严肃穆</li><li><strong>大门</strong>：三座尖拱形大门，中间最大</li><li><strong>玫瑰窗</strong>：直径约3米的圆形玫瑰窗，描绘圣经故事</li></ul><h3 id="内部空间" tabindex="-1">内部空间 <a class="header-anchor" href="#内部空间" aria-label="Permalink to &quot;内部空间&quot;">​</a></h3><ul><li><strong>面积</strong>：建筑面积约2000平方米</li><li><strong>容量</strong>：可同时容纳2000余人</li></ul><h4 id="柱廊与尖拱" tabindex="-1">柱廊与尖拱 <a class="header-anchor" href="#柱廊与尖拱" aria-label="Permalink to &quot;柱廊与尖拱&quot;">​</a></h4><p>内部有两排石柱，支撑尖拱形的天花板。石柱采用科林斯柱式，雕刻精美。</p><h4 id="彩色玻璃窗" tabindex="-1">彩色玻璃窗 <a class="header-anchor" href="#彩色玻璃窗" aria-label="Permalink to &quot;彩色玻璃窗&quot;">​</a></h4><p>教堂两侧的彩色玻璃窗描绘圣经故事和圣人画像，阳光透过彩窗洒入，营造出神圣庄严的氛围。</p><h4 id="祭台与圣像" tabindex="-1">祭台与圣像 <a class="header-anchor" href="#祭台与圣像" aria-label="Permalink to &quot;祭台与圣像&quot;">​</a></h4><p>主祭台供奉救世主耶稣像，两侧有圣母、圣若瑟等圣像。祭台周围有精美的雕塑装饰。</p><h4 id="管风琴" tabindex="-1">管风琴 <a class="header-anchor" href="#管风琴" aria-label="Permalink to &quot;管风琴&quot;">​</a></h4><p>教堂内有一架大型管风琴，是弥撒时的重要乐器。</p><h3 id="中西合璧元素" tabindex="-1">中西合璧元素 <a class="header-anchor" href="#中西合璧元素" aria-label="Permalink to &quot;中西合璧元素&quot;">​</a></h3><p>虽然北堂整体为哥特式建筑，但也有一些中国元素：</p><ul><li>院内有两座中式碑亭</li><li>碑亭内立有乾隆皇帝御笔石碑</li><li>园内种植有中式园林植物</li></ul><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="西什库教案" tabindex="-1">西什库教案 <a class="header-anchor" href="#西什库教案" aria-label="Permalink to &quot;西什库教案&quot;">​</a></h3><p>1900年的义和团运动中，北堂被围攻长达两个月。当时堂内有法国传教士、意大利传教士、中国教友共3000余人。他们依靠少量枪支和坚定信念坚守，最终在西摩尔联军增援下脱险。这是义和团运动中最著名的&quot;西什库教案&quot;。</p><h3 id="康熙与北堂" tabindex="-1">康熙与北堂 <a class="header-anchor" href="#康熙与北堂" aria-label="Permalink to &quot;康熙与北堂&quot;">​</a></h3><p>康熙皇帝对天主教持相对宽容态度。北堂的迁址和扩建都得到了清廷的许可和支持。康熙皇帝还曾题写碑文，表达对传教士科学贡献的肯定。</p><h3 id="中法关系见证" tabindex="-1">中法关系见证 <a class="header-anchor" href="#中法关系见证" aria-label="Permalink to &quot;中法关系见证&quot;">​</a></h3><p>北堂的修建和扩建主要由法国传教士主持，是中法文化交流的重要见证。教堂内的许多装饰和艺术品都来自法国。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="参观建议" tabindex="-1">参观建议 <a class="header-anchor" href="#参观建议" aria-label="Permalink to &quot;参观建议&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：周日上午弥撒后参观，可以感受庄严氛围</li><li><strong>摄影建议</strong>：下午光线从西侧彩窗射入，是拍摄彩窗的最佳时机</li><li><strong>保持安静</strong>：教堂内请保持肃静</li><li><strong>着装得体</strong>：避免过于暴露的着装</li></ol><h3 id="周边游览" tabindex="-1">周边游览 <a class="header-anchor" href="#周边游览" aria-label="Permalink to &quot;周边游览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">俯瞰故宫</td></tr><tr><td style="text-align:left;">故宫神武门</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">故宫北门</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行25分钟</td><td style="text-align:left;">老北京胡同</td></tr></tbody></table><h3 id="弥撒参与" tabindex="-1">弥撒参与 <a class="header-anchor" href="#弥撒参与" aria-label="Permalink to &quot;弥撒参与&quot;">​</a></h3><p>弥撒是天主教最重要的礼仪，游客可以参与旁听。弥撒中有诵经、祈祷、领圣体等环节。非教友可以旁听，但不能领圣体。</p><h2 id="四大教堂对比" tabindex="-1">四大教堂对比 <a class="header-anchor" href="#四大教堂对比" aria-label="Permalink to &quot;四大教堂对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">教堂</th><th style="text-align:left;">建筑风格</th><th style="text-align:center;">年代</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南堂</strong></td><td style="text-align:left;">巴洛克式</td><td style="text-align:center;">1605年</td><td style="text-align:left;">历史最悠久</td></tr><tr><td style="text-align:left;"><strong>北堂</strong></td><td style="text-align:left;">哥特式</td><td style="text-align:center;">1703年</td><td style="text-align:left;">最宏伟华丽</td></tr><tr><td style="text-align:left;"><strong>东堂</strong></td><td style="text-align:left;">罗马式</td><td style="text-align:center;">1655年</td><td style="text-align:left;">位于繁华商业区</td></tr><tr><td style="text-align:left;"><strong>西堂</strong></td><td style="text-align:left;">意大利式</td><td style="text-align:center;">1723年</td><td style="text-align:left;">规模最小</td></tr></tbody></table><p>北堂以其哥特式建筑的宏伟和精美，成为北京天主教堂中最值得一游的地方。</p><hr><p><strong>📍 地址</strong>：北京市西城区西什库大街33号 <strong>📞 电话</strong>：010-66175198 <strong>🌐 弥撒时间</strong>：周日6:30、8:00、10:00、18:00</p>',55)])])}const b=e(n,[["render",i]]);export{c as __pageData,b as default};
